return {
  resource: $('If \'malicious\' or \'suspicious\'').item.json.data.id, 
  type: "IP",
  source_provider: "VirusTotal", 
  scan_date: new Date().toISOString(),
  raw_data: $('VirusTotal IP Scan').item.json.data 
};

const item = $input.item.json;
const raw = item.raw_data || {};
const urls = raw.urls || [];
const mongoId = item.id || null;

const onlineCount = urls.filter(u => u.url_status === 'online').length;

const tagMap = {};
urls.flatMap(u => u.tags || []).forEach(tag => {
    const cleanTag = tag.trim().toLowerCase();
    tagMap[cleanTag] = (tagMap[cleanTag] || 0) + 1;
});

const topTags = Object.entries(tagMap)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(entry => `${entry[0]} (${entry[1]}x)`)
    .join(', ');

const criticalKeywords = ['c2', 'cobaltstrike', 'rat', 'ransomware', 'brute', 'infostealer', 'stealer', 'brat'];
const foundCritical = Object.keys(tagMap).filter(tag => criticalKeywords.includes(tag));

const urlhausRef = raw.urlhaus_reference || "No reference link available";

let report = `SOURCE: Abuse_URLhaus\n`;
if (urls.length === 0 && !raw.urlhaus_reference) {
    report += "STATUS: No data available from this source.";
} else {
    report += `- Total URLs in DB: ${raw.url_count || 0}\n`;
    report += `- Active (Online) URLs: ${onlineCount} / ${urls.length} (analyzed sample)\n`;
    report += `- Top Tags: ${topTags || 'None'}\n`;
    report += `- Reference: ${urlhausRef}\n`; // Dodany atrybut do tekstu

    if (foundCritical.length > 0) {
        report += `- CRITICAL FLAGS DETECTED: ${foundCritical.join(', ').toUpperCase()}\n`;
    }
}

if (urls.length === 0 && !raw.urlhaus_reference) {
    return {
        "urlhaus": {
            "no_data": true,
            "urlhaus_report": "SOURCE: Abuse_URLhaus\nSTATUS: No data available."
        }
    };
}

return {
    "urlhaus": {
        "no_data": false,
        "urlhaus_report": report,
        "is_active_threat": onlineCount > 0,
        "urlhaus_reference": urlhausRef,
        "mongo_id": mongoId
    }
};

const item = $input.item.json;
const raw = item.raw_data || {};
const dataList = raw.data || [];
const mongoId = item.id || null;

const malwareFamilies = [...new Set(dataList.map(d => d.malware_printable).filter(m => m))];
const threatTypes = [...new Set(dataList.map(d => d.threat_type).filter(t => t))];

const confidenceScores = dataList.map(d => d.confidence_level).filter(c => c !== undefined);
const avgConfidence = confidenceScores.length > 0 
    ? (confidenceScores.reduce((a, b) => a + b, 0) / confidenceScores.length).toFixed(0) 
    : 0;

const tagMap = {};
dataList.flatMap(d => d.tags || []).forEach(tag => {
    const cleanTag = tag.trim();
    tagMap[cleanTag] = (tagMap[cleanTag] || 0) + 1;
});
const topTags = Object.entries(tagMap)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(e => e[0])
    .join(', ');

const externalRef = dataList.length > 0 ? dataList[0].reference : "No reference available";

let report = `SOURCE: Abuse_ThreatFox\n`;
if (dataList.length === 0 || raw.query_status !== "ok") {
    report += "STATUS: No indicators found for this resource.";
} else {
    report += `- Detections Found: ${dataList.length}\n`;
    report += `- Malware Families: ${malwareFamilies.join(', ') || 'Unknown'}\n`;
    report += `- Threat Types: ${threatTypes.join(', ') || 'Unknown'}\n`;
    report += `- Average Confidence: ${avgConfidence}%\n`;
    report += `- Top Tags: ${topTags || 'None'}\n`;
    report += `- Reference: ${externalRef}\n`;
}

if (dataList.length === 0 || raw.query_status !== "ok") {
    return {
        "threatfox": {
            "no_data": true,
            "threatfox_report": "SOURCE: Abuse_ThreatFox\nSTATUS: No indicators found.",
            "mongo_id": mongoId
        }
    };
}

return {
    "threatfox": {
        "no_data": false,
        "threatfox_report": report,
        "threatfox_active": dataList.length > 0,
        "threatfox_max_confidence": Math.max(...confidenceScores, 0),
        "mongo_id": mongoId
    }
};

// Get item from n8n input
const item = $input.item.json;

const mongoId = item.id || null;

// Target the correct path in your specific JSON
const attr = item.raw_data && item.raw_data.attributes ? item.raw_data.attributes : {};

// 1. Get Analysis Stats
const stats = attr.last_analysis_stats || {};
const malCount = stats.malicious || 0;
const susCount = stats.suspicious || 0;
const undCount = stats.undetected || 0;

// 2. Get Engines that flagged it (Malicious/Suspicious)
const results = attr.last_analysis_results || {};
const flaggedBy = [];

Object.keys(results).forEach(engine => {
    if (results[engine].category === 'malicious' || results[engine].category === 'suspicious') {
        flaggedBy.push(`${engine} (${results[engine].result})`);
    }
});

// 3. Network & Ownership
const asOwner = attr.as_owner || "Unknown Owner";
const network = attr.network || "Unknown Network";
const rdap = attr.rdap || {};
const ipRange = (rdap.start_address && rdap.end_address) 
    ? `${rdap.start_address} - ${rdap.end_address}` 
    : "Range not specified";

// 4. Build the report string
let report = `SOURCE: VirusTotal\n`;
report += `- Owner: ${asOwner}\n`;
report += `- Network: ${network}\n`;
report += `- IP Range: ${ipRange}\n`;
report += `- Stats: Malicious: ${malCount}, Suspicious: ${susCount}, Undetected: ${undCount}\n`;

if (flaggedBy.length > 0) {
    report += `- Flagged by: ${flaggedBy.join(', ')}\n`;
}

// 5. Check if it's a Big Player
const bigPlayers = ["github", "google", "microsoft", "amazon", "cloudflare"];
const isBigPlayer = bigPlayers.some(p => asOwner.toLowerCase().includes(p));

if (!item.raw_data || !item.raw_data.attributes) {
    return {
        "virustotal": {
            "no_data": true,
            "vt_report": "SOURCE: VirusTotal\nSTATUS: No data found for this resource.",
            "mongo_id": mongoId
        }
    };
}

return {
    "virustotal": {
        "no_data": false,
        "vt_report": report,
        "vt_stats": stats,
        "vt_owner": asOwner,
        "vt_is_big_player": isBigPlayer,
        "vt_malicious_count": malCount,
        "vt_scan_date": item.scan_date,
        "mongo_id": mongoId
    }
};

// Łączymy wszystkie elementy z wejścia w jeden obiekt
let combinedData = {};

for (const item of $input.all()) {
  // Scalamy właściwości (np. virustotal, threatfox, urlhaus) w jeden obiekt
  Object.assign(combinedData, item.json);
}

return combinedData;
